// Parser la sortie de itsm-sync.py --backend jira
const stdout = $input.item.json.stdout || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Extraire le vrai code de sortie
let realExit = exitCode;
const exitMatch = stdout.match(/EXIT:(\d+)/);
if (exitMatch) realExit = parseInt(exitMatch[1]);

// Extraire les clés JIRA créées (pattern PROJECT_KEY-NUMBER, ex: NOC-42, NETWATCH-7)
const jiraKeyPattern = /\b([A-Z][A-Z0-9]+-\d+)\b/g;
const jiraMatches = [...stdout.matchAll(jiraKeyPattern)];
const jiraKeys = [...new Set(jiraMatches.map(m => m[1]))];

// Extraire les compteurs depuis le résumé
const createdMatch = stdout.match(/Créés\s*:\s*(\d+)/);
const failedMatch  = stdout.match(/Echecs\s*:\s*(\d+)/);
const skippedMatch = stdout.match(/Skippés\s*:\s*(\d+)/);

const createdCount = createdMatch ? parseInt(createdMatch[1]) : jiraKeys.length;
const failedCount  = failedMatch  ? parseInt(failedMatch[1])  : 0;
const skippedCount = skippedMatch ? parseInt(skippedMatch[1]) : 0;

// Extraire le projet JIRA depuis la première clé (ex: NOC de NOC-42)
const projectKey = jiraKeys.length > 0 ? jiraKeys[0].split('-')[0] : 'NOC';

console.log(`[jira-sync] exit=${realExit} | créés=${createdCount} | echecs=${failedCount} | skippés=${skippedCount}`);
console.log(`[jira-sync] issues créées: ${jiraKeys.join(', ') || 'aucune'}`);

return [{
  json: {
    stdout,
    exitCode: realExit,
    createdCount,
    failedCount,
    skippedCount,
    jiraKeys,
    projectKey,
    hasCreated: createdCount > 0,
    timestamp: new Date().toISOString()
  }
}];

// Construire la carte Teams pour JIRA
const {
  createdCount, failedCount, skippedCount, jiraKeys, projectKey, timestamp
} = $input.item.json;

const dateStr = new Date(timestamp).toLocaleString('fr-FR', {
  timeZone: 'Europe/Paris',
  dateStyle: 'short',
  timeStyle: 'short'
});

// Liste des issues créées (max 10)
const keyList = jiraKeys.slice(0, 10).join(', ');
const keyMore = jiraKeys.length > 10 ? ` (+${jiraKeys.length - 10} autres)` : '';

const payload = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          text: `NetWatch → JIRA [${projectKey}] — ${dateStr}`,
          weight: 'Bolder',
          size: 'Large',
          color: 'Accent',
          wrap: true
        },
        {
          type: 'TextBlock',
          text: `${createdCount} issue(s) créée(s) dans JIRA [${projectKey}]`,
          size: 'Medium',
          wrap: true
        },
        {
          type: 'FactSet',
          facts: [
            { title: 'Créées',   value: String(createdCount) },
            { title: 'Echecs',   value: String(failedCount) },
            { title: 'Skippées', value: String(skippedCount) },
            { title: 'Issues',   value: keyList + keyMore || 'N/A' }
          ]
        }
      ],
      actions: [{
        type: 'Action.OpenUrl',
        title: 'Ouvrir NetWatch',
        url: 'http://localhost:5050'
      }]
    }
  }]
};

return [{ json: payload }];
